        AscendC::DataCopy(biasLocal_, biasGm_, totalO_);
        AscendC::DataCopy(gammaLocal_, gnGammaGm_, totalO_);
        AscendC::DataCopy(betaLocal_, gnBetaGm_, totalO_);
